import { useEffect, useState } from "react";
import { indiceApi } from "../services/api";

const Indice = () => {
  const [indices, setIndices] = useState([]);
  const [tendances, setTendances] = useState(null);

  useEffect(() => {
    indiceApi.list().then((r) => setIndices(r.data.data || []));
    indiceApi.tendances().then((r) => setTendances(r.data));
  }, []);

  return (
    <div className="space-y-4">
      <h2 className="text-2xl font-semibold">Indices par zone</h2>
      {tendances && (
        <div className="grid md:grid-cols-3 gap-4">
          <div className="bg-white p-4 rounded shadow">Hausse: {tendances.HAUSSE.count}</div>
          <div className="bg-white p-4 rounded shadow">Stable: {tendances.STABLE.count}</div>
          <div className="bg-white p-4 rounded shadow">Baisse: {tendances.BAISSE.count}</div>
        </div>
      )}
      <div className="bg-white p-4 rounded shadow overflow-auto">
        <table className="w-full text-sm">
          <thead><tr><th>Zone</th><th>Période</th><th>Indice</th><th>Tendance</th></tr></thead>
          <tbody>{indices.map((i) => <tr key={i.id}><td>{i.zone}</td><td>{i.periode}</td><td>{i.indice_valeur}</td><td>{i.tendance}</td></tr>)}</tbody>
        </table>
      </div>
    </div>
  );
};

export default Indice;
